// Extrai dados da mensagem Evolution API (MESSAGES_UPSERT)
const raw = $input.first().json;
// Acesso o body que vem aninhado no primeiro item do array
let body = raw[0]?.body || raw.body || raw;

// Se for requisição de atualização de config vinda do CRM
if (body.action === 'update_agent_config') {
    const staticData = $getWorkflowStaticData('global');
    staticData.agentConfig = body;
    return [];
}

// Garante que é um evento de mensagem
if (body.event !== 'messages.upsert') {
    throw new Error('DEBUG: Evento ignorado (Não é messages.upsert). Evento foi: ' + body.event);
}

// A DbConecta várias vezes manda a mensagem direto em body.data (sem array messages)
const msg = body.data?.messages?.[0] || body.data;
if (!msg || (!msg.message && !msg.messageStubType)) {
    throw new Error('DEBUG: Sem msg ou msg.message. Payload da message: ' + JSON.stringify(msg));
}

// Ignora msgs de grupos, status, ou enviadas por nós
if (msg.key?.fromMe) throw new Error('DEBUG: Mensagem ignorada (Enviada por mim).');
if (msg.key?.remoteJid?.includes('@g.us') || msg.key?.remoteJid?.includes('status')) {
    throw new Error('DEBUG: Mensagem ignorada (Grupo ou Status).');
}

// Tenta extrair o número, priorizando o remoteJidAlt se for addressingMode: lid
const rawPhone = msg.key?.remoteJidAlt || msg.key?.remoteJid || '';
const phone = String(rawPhone).replace(/\D/g, '');

// Extrai texto
const message = msg.message?.conversation 
  || msg.message?.extendedTextMessage?.text 
  || msg.message?.imageMessage?.caption 
  || msg.message?.videoMessage?.caption 
  || '';

// Extrai nome
const name = msg.pushName || 'Lead';

// Se extraiu algo prático mas falhou
if (!phone || !message.trim()) {
    throw new Error(`DEBUG: Falha na extração final. Telefone extraído: '${phone}', Texto extraído: '${message}'`);
}

return [{ json: { phone, message: message.trim(), name } }];

// Carrega e salva histórico de conversa por telefone (memória local)
const staticData = $getWorkflowStaticData('global');
const phone      = $input.first().json.phone;
const message    = $input.first().json.message;
const name       = $input.first().json.name;

const key     = 'hist_' + phone;
const history = staticData[key] || [];

// Adiciona mensagem do lead
history.push({ role: 'user', content: `[${name}]: ${message}` });

// Limita a 20 mensagens (10 trocas)
if (history.length > 20) history.splice(0, history.length - 20);

staticData[key] = history;

return [{ json: { phone, name, message, history, historyKey: key } }];

// Processa resposta do GPT e salva no histórico
const historyKey = $('Carregar Histórico').first().json.historyKey;
const phone      = $('Carregar Histórico').first().json.phone;
const gptBody    = $input.first().json;
const reply      = gptBody.choices?.[0]?.message?.content || 'Desculpe, tive um problema técnico. Pode repetir?';

// Salva resposta do assistente no histórico
const staticData = $getWorkflowStaticData('global');
const history    = staticData[historyKey] || [];
history.push({ role: 'assistant', content: reply });
if (history.length > 20) history.splice(0, history.length - 20);
staticData[historyKey] = history;

return [{ json: { phone, reply } }];

// Se a IA estiver desativada para este número, para o workflow
const aiStatus = $input.first().json;
const histData = $('Carregar Histórico').first().json;

// Se erro na chamada ou aiEnabled=false, para aqui
if (aiStatus.aiEnabled === false) {
  console.log('[SDR] IA desativada para ' + histData.phone + '. Modo manual ativo.');
  return []; // Para o workflow — não envia resposta
}

// Passa os dados do histórico para o próximo node
return [{ json: histData }];

// Monta o prompt dinâmico baseado na config salva
const staticData = $getWorkflowStaticData('global');
const cfg = staticData.agentConfig || {
  agentName: 'SDR da PromptX',
  systemPrompt: 'Você é um assistente útil focado em marcar calls.',
  restrictions: ['Nunca revelar preço antes da call', 'Nunca falar que é IA'],
  skills: ['Qualificar leads', 'Agendar reuniões'],
  flow: ['1. Primeiro contato', '2. Relacionamento', '3. Agendamento']
};

let prompt = `${cfg.systemPrompt}\n\n`;

if (cfg.restrictions && cfg.restrictions.length > 0) {
    prompt += `REGRAS ABSOLUTAS:\n- ${cfg.restrictions.join('\n- ')}\n\n`;
}

if (cfg.skills && cfg.skills.length > 0) {
    prompt += `HABILIDADES E INFORMAÇÕES:\n- ${cfg.skills.join('\n- ')}\n\n`;
}

if (cfg.flow && cfg.flow.length > 0) {
    prompt += `FLUXO DE CONVERSA:\n${cfg.flow.map((f, i) => `${i+1}. ${f}`).join('\n')}\n\n`;
}

if (cfg.calLink) {
    prompt += `LINK DE AGENDAMENTO: ${cfg.calLink}\n\n`;
}

prompt += `FORMATO DA MENSAGEM: Seja natural, não pareça um robô. Responda de forma curta (máx 3 linhas) e sempre termine com uma pergunta no final.`;

return [{ json: { ...$input.first().json, dynamicPrompt: prompt } }];
